code = """import os, json, re

# Read non-Python repos data
with open('var_functions.query_db:112', 'r') as f:
    non_python_repos = json.load(f)

# Read README contents data  
with open('var_functions.query_db:120', 'r') as f:
    readme_data = json.load(f)

print("Non-Python repos:", len(non_python_repos))
print("README files:", len(readme_data))

# Create set of non-Python repo names
non_python_names = set([item['repo_name'] for item in non_python_repos])
print("Unique non-Python repos:", len(non_python_names))

# Filter READMEs and check for copyright
non_python_readmes = []
copyright_count = 0
copyright_pattern = re.compile(r'copyright', re.IGNORECASE)

for readme in readme_data:
    repo_name = readme.get('sample_repo_name')
    if repo_name and repo_name in non_python_names:
        non_python_readmes.append(readme)
        if copyright_pattern.search(readme.get('content', '')):
            copyright_count += 1

total = len(non_python_readmes)
proportion = copyright_count / total if total > 0 else 0

print("\nAnalysis Results:")
print("Total non-Python READMEs:", total)
print("READMEs with copyright:", copyright_count)
print("Proportion:", f"{proportion:.2%}")

result = {
    "total_non_python_readmes": total,
    "copyright_count": copyright_count,
    "proportion": round(proportion, 4)
}

print("__RESULT__:")
print(json.dumps(result))"""

